1198 static Value *canonicalizeSPF(ICmpInst &Cmp, Value *TrueVal, Value *FalseVal,
1199                               InstCombinerImpl &IC) {
1200   Value *LHS, *RHS;
1201   // TODO: What to do with pointer min/max patterns?
1202   if (!TrueVal->getType()->isIntOrIntVectorTy())
1203     return nullptr;
1204 
1205   SelectPatternFlavor SPF =
1206       matchDecomposedSelectPattern(&Cmp, TrueVal, FalseVal, LHS, RHS).Flavor;
1207   if (SPF == SelectPatternFlavor::SPF_ABS ||
1208       SPF == SelectPatternFlavor::SPF_NABS) {
1209     if (!Cmp.hasOneUse() && !RHS->hasOneUse())
1210       return nullptr; // TODO: Relax this restriction.
1211 
1212     // Note that NSW flag can only be propagated for normal, non-negated abs!
1213     bool IntMinIsPoison = SPF == SelectPatternFlavor::SPF_ABS &&
1214                           match(RHS, m_NSWNeg(m_Specific(LHS)));
1215     Constant *IntMinIsPoisonC =
1216         ConstantInt::get(Type::getInt1Ty(Cmp.getContext()), IntMinIsPoison);
1217     Value *Abs =
1218         IC.Builder.CreateBinaryIntrinsic(Intrinsic::abs, LHS, IntMinIsPoisonC);
1219 
1220     if (SPF == SelectPatternFlavor::SPF_NABS)
1221       return IC.Builder.CreateNeg(Abs); // Always without NSW flag!
1222     return Abs;
1223   }
1224 
1225   if (SelectPatternResult::isMinOrMax(SPF)) {
1226     Intrinsic::ID IntrinsicID = getMinMaxIntrinsic(SPF);
1227     return IC.Builder.CreateBinaryIntrinsic(IntrinsicID, LHS, RHS);
1228   }
1229 
1230   return nullptr;
