8231 /// Recognize variations of:
8232 ///   a < c ? min(a,b) : min(b,c) ==> min(min(a,b),min(b,c))
8233 static SelectPatternResult matchMinMaxOfMinMax(CmpInst::Predicate Pred,
8234                                                Value *CmpLHS, Value *CmpRHS,
8235                                                Value *TVal, Value *FVal,
8236                                                unsigned Depth) {
8237   // TODO: Allow FP min/max with nnan/nsz.
8238   assert(CmpInst::isIntPredicate(Pred) && "Expected integer comparison");
8239 
8240   Value *A = nullptr, *B = nullptr;
8241   SelectPatternResult L = matchSelectPattern(TVal, A, B, nullptr, Depth + 1);
8242   if (!SelectPatternResult::isMinOrMax(L.Flavor))
8243     return {SPF_UNKNOWN, SPNB_NA, false};
8244 
8245   Value *C = nullptr, *D = nullptr;
8246   SelectPatternResult R = matchSelectPattern(FVal, C, D, nullptr, Depth + 1);
8247   if (L.Flavor != R.Flavor)
8248     return {SPF_UNKNOWN, SPNB_NA, false};
8249 
8250   // We have something like: x Pred y ? min(a, b) : min(c, d).
8251   // Try to match the compare to the min/max operations of the select operands.
8252   // First, make sure we have the right compare predicate.
8253   switch (L.Flavor) {
8254   case SPF_SMIN:
8255     if (Pred == ICmpInst::ICMP_SGT || Pred == ICmpInst::ICMP_SGE) {
8256       Pred = ICmpInst::getSwappedPredicate(Pred);
8257       std::swap(CmpLHS, CmpRHS);
8258     }
8259     if (Pred == ICmpInst::ICMP_SLT || Pred == ICmpInst::ICMP_SLE)
8260       break;
8261     return {SPF_UNKNOWN, SPNB_NA, false};
8262   case SPF_SMAX:
8263     if (Pred == ICmpInst::ICMP_SLT || Pred == ICmpInst::ICMP_SLE) {
8264       Pred = ICmpInst::getSwappedPredicate(Pred);
8265       std::swap(CmpLHS, CmpRHS);
8266     }
8267     if (Pred == ICmpInst::ICMP_SGT || Pred == ICmpInst::ICMP_SGE)
8268       break;
8269     return {SPF_UNKNOWN, SPNB_NA, false};
8270   case SPF_UMIN:
8271     if (Pred == ICmpInst::ICMP_UGT || Pred == ICmpInst::ICMP_UGE) {
8272       Pred = ICmpInst::getSwappedPredicate(Pred);
8273       std::swap(CmpLHS, CmpRHS);
8274     }
8275     if (Pred == ICmpInst::ICMP_ULT || Pred == ICmpInst::ICMP_ULE)
8276       break;
8277     return {SPF_UNKNOWN, SPNB_NA, false};
8278   case SPF_UMAX:
8279     if (Pred == ICmpInst::ICMP_ULT || Pred == ICmpInst::ICMP_ULE) {
8280       Pred = ICmpInst::getSwappedPredicate(Pred);
8281       std::swap(CmpLHS, CmpRHS);
8282     }
8283     if (Pred == ICmpInst::ICMP_UGT || Pred == ICmpInst::ICMP_UGE)
8284       break;
8285     return {SPF_UNKNOWN, SPNB_NA, false};
8286   default:
8287     return {SPF_UNKNOWN, SPNB_NA, false};
8288   }
8289 
8290   // If there is a common operand in the already matched min/max and the other
8291   // min/max operands match the compare operands (either directly or inverted),
8292   // then this is min/max of the same flavor.
8293 
8294   // a pred c ? m(a, b) : m(c, b) --> m(m(a, b), m(c, b))
8295   // ~c pred ~a ? m(a, b) : m(c, b) --> m(m(a, b), m(c, b))
8296   if (D == B) {
8297     if ((CmpLHS == A && CmpRHS == C) || (match(C, m_Not(m_Specific(CmpLHS))) &&
8298                                          match(A, m_Not(m_Specific(CmpRHS)))))
8299       return {L.Flavor, SPNB_NA, false};
8300   }
8301   // a pred d ? m(a, b) : m(b, d) --> m(m(a, b), m(b, d))
8302   // ~d pred ~a ? m(a, b) : m(b, d) --> m(m(a, b), m(b, d))
8303   if (C == B) {
8304     if ((CmpLHS == A && CmpRHS == D) || (match(D, m_Not(m_Specific(CmpLHS))) &&
8305                                          match(A, m_Not(m_Specific(CmpRHS)))))
8306       return {L.Flavor, SPNB_NA, false};
8307   }
8308   // b pred c ? m(a, b) : m(c, a) --> m(m(a, b), m(c, a))
8309   // ~c pred ~b ? m(a, b) : m(c, a) --> m(m(a, b), m(c, a))
8310   if (D == A) {
8311     if ((CmpLHS == B && CmpRHS == C) || (match(C, m_Not(m_Specific(CmpLHS))) &&
8312                                          match(B, m_Not(m_Specific(CmpRHS)))))
8313       return {L.Flavor, SPNB_NA, false};
8314   }
8315   // b pred d ? m(a, b) : m(a, d) --> m(m(a, b), m(a, d))
8316   // ~d pred ~b ? m(a, b) : m(a, d) --> m(m(a, b), m(a, d))
8317   if (C == A) {
8318     if ((CmpLHS == B && CmpRHS == D) || (match(D, m_Not(m_Specific(CmpLHS))) &&
8319                                          match(B, m_Not(m_Specific(CmpRHS)))))
8320       return {L.Flavor, SPNB_NA, false};
8321   }
8322 
8323   return {SPF_UNKNOWN, SPNB_NA, false};
8324 }
